import{_ as a,o as t,c as o,a4 as r}from"./chunks/framework.BZxhJ0Uw.js";const b=JSON.parse('{"title":"Interface: EventLoopOptions · ui","description":"","frontmatter":{"title":"Interface: EventLoopOptions · ui"},"headers":[],"relativePath":"api/ui/interfaces/EventLoopOptions.md","filePath":"api/ui/interfaces/EventLoopOptions.md"}'),n={name:"api/ui/interfaces/EventLoopOptions.md"};function c(s,e,d,i,l,p){return t(),o("div",null,[...e[0]||(e[0]=[r('<p><a href="./../">@jsvision/ui</a> / EventLoopOptions</p><h1 id="interface-eventloopoptions" tabindex="-1">Interface: EventLoopOptions <a class="header-anchor" href="#interface-eventloopoptions" aria-label="Permalink to &quot;Interface: EventLoopOptions&quot;">​</a></h1><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d26af6b65fdb930cbfa9dd38a019cc4e72acb595/packages/ui/src/event/types.ts#L36" target="_blank" rel="noreferrer">ui/src/event/types.ts:36</a></p><p>Options for <a href="./../functions/createEventLoop.html">createEventLoop</a>. Only <code>caps</code> is required; everything else is optional.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h2><h3 id="caps" tabindex="-1">caps <a class="header-anchor" href="#caps" aria-label="Permalink to &quot;caps&quot;">​</a></h3><blockquote><p><strong>caps</strong>: <a href="./CapabilityProfile.html"><code>CapabilityProfile</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d26af6b65fdb930cbfa9dd38a019cc4e72acb595/packages/ui/src/event/types.ts#L38" target="_blank" rel="noreferrer">ui/src/event/types.ts:38</a></p><p>Required. Terminal capability profile that drives color-depth encoding for every painted frame.</p><hr><h3 id="commands" tabindex="-1">commands? <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;commands?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>commands?</strong>: <code>Iterable</code>&lt;<code>string</code>, <code>any</code>, <code>any</code>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d26af6b65fdb930cbfa9dd38a019cc4e72acb595/packages/ui/src/event/types.ts#L46" target="_blank" rel="noreferrer">ui/src/event/types.ts:46</a></p><p>Optional list of command names known up front. Commands are enabled by default whether listed or not.</p><hr><h3 id="keymap" tabindex="-1">keymap? <a class="header-anchor" href="#keymap" aria-label="Permalink to &quot;keymap?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>keymap?</strong>: <a href="./Keymap.html"><code>Keymap</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d26af6b65fdb930cbfa9dd38a019cc4e72acb595/packages/ui/src/event/types.ts#L44" target="_blank" rel="noreferrer">ui/src/event/types.ts:44</a></p><p>Key-chord → command map (from core&#39;s <code>createKeymap</code>): a matched chord fires the command and swallows the key.</p><hr><h3 id="logger" tabindex="-1">logger? <a class="header-anchor" href="#logger" aria-label="Permalink to &quot;logger?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>logger?</strong>: <code>Logger</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d26af6b65fdb930cbfa9dd38a019cc4e72acb595/packages/ui/src/event/types.ts#L42" target="_blank" rel="noreferrer">ui/src/event/types.ts:42</a></p><p>Logger that receives errors thrown from a view&#39;s <code>onEvent()</code>/<code>draw()</code>; defaults to a no-op logger.</p><hr><h3 id="now" tabindex="-1">now? <a class="header-anchor" href="#now" aria-label="Permalink to &quot;now?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>now?</strong>: () =&gt; <code>number</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d26af6b65fdb930cbfa9dd38a019cc4e72acb595/packages/ui/src/event/types.ts#L54" target="_blank" rel="noreferrer">ui/src/event/types.ts:54</a></p><p>Clock used to time double-clicks (defaults to <code>Date.now</code>). Two mouse-downs on the same cell within the multi-click window are reported as a double-click via <code>DispatchEvent.clickCount</code>. Inject a controllable clock in headless tests to drive exact timestamps.</p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>number</code></p><hr><h3 id="onidle" tabindex="-1">onIdle? <a class="header-anchor" href="#onidle" aria-label="Permalink to &quot;onIdle?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>onIdle?</strong>: () =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d26af6b65fdb930cbfa9dd38a019cc4e72acb595/packages/ui/src/event/types.ts#L48" target="_blank" rel="noreferrer">ui/src/event/types.ts:48</a></p><p>Called once per dispatch tick after all cascaded events drain, just before the frame is painted.</p><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="onquit" tabindex="-1">onQuit? <a class="header-anchor" href="#onquit" aria-label="Permalink to &quot;onQuit?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>onQuit?</strong>: (<code>code</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d26af6b65fdb930cbfa9dd38a019cc4e72acb595/packages/ui/src/event/types.ts#L73" target="_blank" rel="noreferrer">ui/src/event/types.ts:73</a></p><p>Called when the <a href="#quitcommand">quitCommand</a> is emitted, with the exit code carried by the command (0 when none was given). This is how the loop terminates: <code>createApplication</code> wires it to resolve <code>run()</code>. When unset (a bare loop), the quit command is a plain command with no special termination.</p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="code" tabindex="-1">code <a class="header-anchor" href="#code" aria-label="Permalink to &quot;code&quot;">​</a></h5><p><code>number</code></p><h4 id="returns-2" tabindex="-1">Returns <a class="header-anchor" href="#returns-2" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="quitcommand" tabindex="-1">quitCommand? <a class="header-anchor" href="#quitcommand" aria-label="Permalink to &quot;quitCommand?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>quitCommand?</strong>: <code>string</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d26af6b65fdb930cbfa9dd38a019cc4e72acb595/packages/ui/src/event/types.ts#L61" target="_blank" rel="noreferrer">ui/src/event/types.ts:61</a></p><p>The command that terminates the app (default <code>&#39;quit&#39;</code>). If a quit is emitted while modal windows are open, it cascades top-down through the modal stack: each modal is asked to close, and a modal that vetoes (e.g. a dialog whose validation fails) stops the cascade and keeps the app running. Once the stack is empty the quit reaches the app&#39;s quit handler.</p><hr><h3 id="revealkey" tabindex="-1">revealKey? <a class="header-anchor" href="#revealkey" aria-label="Permalink to &quot;revealKey?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>revealKey?</strong>: <code>string</code> | <code>null</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d26af6b65fdb930cbfa9dd38a019cc4e72acb595/packages/ui/src/event/types.ts#L67" target="_blank" rel="noreferrer">ui/src/event/types.ts:67</a></p><p>The key that toggles &quot;accelerator mode&quot; (default <code>&#39;f12&#39;</code>). While it is on, every reachable <code>~X~</code> hotkey in the current scope is underlined and pressing a bare letter fires the matching accelerator as if you had pressed <code>Alt</code>+letter. Pass <code>null</code> to disable the feature entirely.</p><hr><h3 id="theme" tabindex="-1">theme? <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;theme?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>theme?</strong>: <code>Theme</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d26af6b65fdb930cbfa9dd38a019cc4e72acb595/packages/ui/src/event/types.ts#L40" target="_blank" rel="noreferrer">ui/src/event/types.ts:40</a></p><p>Color/style theme applied to every view; defaults to the built-in <code>defaultTheme</code>.</p>',63)])])}const u=a(n,[["render",c]]);export{b as __pageData,u as default};
